import React from 'react';

function App() {
  return (
    <div style={{
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      minHeight: '100vh',
      backgroundColor: '#1a1a2e',
      color: 'white',
      flexDirection: 'column'
    }}>
      <h1 style={{ fontSize: '48px' }}>🚀 TeamFlow</h1>
      <p style={{ color: '#888' }}>App is working!</p>
      <p style={{ color: '#666', fontSize: '14px' }}>Now we can add the login page</p>
    </div>
  );
}

export default App;
